/*package*/ interface Intf {
    String CONST = "constant";
    public static final String CONST2 = "constant";

    void method1();
    public abstract void method2();

    default void method3() {};
    public default void method4() {};

    class MemberClass {}
    public static class MemberClass2 {}

    enum MemberEnum { A }
    public enum MemberEnum2 { A }
}

/*package*/ @interface Annot {
    String value();
    public String value2();
}

/*package*/ class TopLevel {
    public interface PublicIntf {} // violation here
    /*package*/ interface Intf {
        // fields are implicit public
        String CONST = "constant";
        public static final String CONST2 = "constant";

        void method1();
        public abstract void method2();

        default void method3() {};
        public default void method4() {};

        class MemberClass {}
        public static class MemberClass2 {}
    }

    /*package*/ @interface Annot {
        String value();
    }
}

public class Parent {
    public void foo() { }
    void bar() { }
}

class Child extends Parent {
    @Override
    public void foo() { }  // this has to be public, because an overriding method has to be at least as visible as the overridden one

    @Override
    public void bar() { }  // violation, because this can be default visibility
}

public interface I {
    public void foo() { }
    void bar() { }
}

class Child extends Parent {
    @Override
    public void foo() { }  // this has to be public

    @Override
    public void bar() { }  // this has to be public, too
}
